INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_031', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(a)', 'WIC § 300(a)', 'Serious Physical Harm Inflicted by Parent', 'Child has suffered or is at substantial risk of suffering serious physical harm inflicted nonaccidentally by the parent or guardian.', '["Nonaccidental serious physical harm by parent/guardian","Substantial risk of future harm sufficient","Age-appropriate spanking to buttocks is excluded","Includes willful or negligent cruelty by any household member"]', '[{"section":"300(a)","description":"Serious physical harm inflicted nonaccidentally upon the minor by the parent or guardian"}]', '["dependency_petition","detention_report","jurisdiction_disposition_report","CPS_referral"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_032', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(b)(1)', 'WIC § 300(b)(1)', 'Failure to Protect — Serious Physical Harm or Illness', 'Child has suffered or is at substantial risk of suffering serious physical harm or illness as a result of the failure or inability of the parent to adequately supervise or protect the child.', '["Failure or inability to supervise or protect","Failure to provide adequate food, clothing, shelter, or medical treatment","Inability to provide regular care due to substance abuse or mental illness","No requirement of parental fault — focus is on child safety"]', '[{"section":"300(b)(1)","description":"Neglect — failure to protect from serious physical harm or illness"}]', '["dependency_petition","detention_report","medical_records","CPS_referral","substance_abuse_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_033', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(c)', 'WIC § 300(c)', 'Serious Emotional Damage', 'Child is suffering serious emotional damage or is at substantial risk of suffering serious emotional damage evidenced by severe anxiety, depression, withdrawal, or untoward aggressive behavior.', '["Serious emotional damage — not speculative","Evidenced by severe anxiety, depression, withdrawal, or aggression","No reasonable means for parent to protect without court intervention","Professional assessment typically required"]', '[{"section":"300(c)","description":"Serious emotional damage caused by conduct of parent or guardian or who has no parent capable of providing care"}]', '["dependency_petition","psychological_evaluation","school_records","therapist_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_034', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(d)', 'WIC § 300(d)', 'Sexual Abuse', 'Child has been sexually abused or there is substantial risk of being sexually abused by parent, guardian, or household member, or the parent has failed to adequately protect the child.', '["Sexual abuse as defined in Penal Code § 11165.1","Includes acts by parent, guardian, or household member","Substantial risk of future abuse sufficient","Parent failure to protect from known abuser"]', '[{"section":"300(d)","description":"Sexual abuse or substantial risk thereof — cross-references Penal Code § 11165.1"}]', '["dependency_petition","forensic_interview","SART_exam","CPS_referral","law_enforcement_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_035', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(e)', 'WIC § 300(e)', 'Severe Physical Abuse — Under Age 5', 'Child under age five has suffered severe physical abuse by a parent or any person known to the parent, if the parent knew or reasonably should have known the person was physically abusing the child.', '["Applies to children under age 5","Severe physical abuse — single or multiple acts","Parent knew or should have known of abuse","Triggers bypass of reunification services under § 361.5(b)"]', '[{"section":"300(e)","description":"Severe physical abuse of child under 5 — defined by reference to PC § 273a and severe injuries"}]', '["dependency_petition","medical_records","forensic_exam","detention_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_036', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(f)', 'WIC § 300(f)', 'Death of Child by Parent Abuse or Neglect', 'The child''s parent or guardian caused the death of another child through abuse or neglect.', '["Prior child death caused by parent abuse or neglect","Triggers bypass of reunification services under § 361.5(b)","Criminal conviction not required — civil standard applies","Includes death of any child, not limited to sibling"]', '[{"section":"300(f)","description":"Parent caused death of another child through abuse or neglect"}]', '["dependency_petition","death_certificate","coroner_report","criminal_records","prior_CPS_history"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_037', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(g)', 'WIC § 300(g)', 'Left Without Provision for Support', 'Child has been left without any provision for support, or parent has been incarcerated or institutionalized and cannot arrange for care of the child.', '["Child left without provision for support","Parent incarcerated or institutionalized","No reasonable plan for child care by parent","Voluntary surrender or abandonment"]', '[{"section":"300(g)","description":"No provision for support — incarceration, institutionalization, or abandonment"}]', '["dependency_petition","detention_report","incarceration_records","social_worker_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_038', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(h)', 'WIC § 300(h)', 'Freed for Adoption but Not Placed', 'Child has been freed for adoption by one or both parents for 12 months by either relinquishment or termination of parental rights, and has not been adopted.', '["Parental rights terminated or relinquished","12-month period without adoption placement","Agency must demonstrate diligent efforts to place","Court may order additional efforts or alternative plan"]', '[{"section":"300(h)","description":"Freed for adoption for 12+ months without placement"}]', '["adoption_assessment","TPR_order","placement_report","permanency_plan"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_039', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(i)', 'WIC § 300(i)', 'Cruelty', 'Child has been subjected to an act or acts of cruelty by the parent or guardian or a member of the household, or the parent has failed to adequately protect the child from such acts.', '["Acts of cruelty by parent, guardian, or household member","Includes acts that endanger child health or well-being","Parent failure to protect from cruelty by others","May overlap with 300(a) but broader scope"]', '[{"section":"300(i)","description":"Cruelty — acts endangering child health, person, or well-being"}]', '["dependency_petition","CPS_referral","medical_records","law_enforcement_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_040', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 300(j)', 'WIC § 300(j)', 'Sibling Abuse or Neglect', 'Child''s sibling has been abused or neglected as defined in subdivisions (a), (b), (d), (e), or (i), and there is a substantial risk that the child will be abused or neglected.', '["Sibling was abused/neglected under 300(a),(b),(d),(e), or (i)","Substantial risk that this child will also be abused or neglected","Court considers circumstances of sibling abuse","Court considers age and gender of each child"]', '[{"section":"300(j)","description":"Sibling abuse/neglect with substantial risk to subject child"}]', '["dependency_petition","prior_CPS_history","sibling_case_records","detention_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));


