INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_041', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 361.5', 'WIC § 361.5', 'Reunification Services', 'Governs when reunification services must be provided and when they may be bypassed in dependency proceedings.', '["Reunification services required unless bypass applies","6 months for children under 3, 12 months for older children","18 months maximum in most cases","Bypass grounds include severe abuse (300(e)), sibling death (300(f)), chronic abuse, prior failed reunification"]', '[{"section":"361.5(a)","description":"Mandatory reunification services upon removal"},{"section":"361.5(b)","description":"Bypass grounds — enumerated exceptions to reunification"},{"section":"361.5(e)","description":"No services if parent not provided with reasonable services in prior case"}]', '["reunification_plan","case_plan","status_review_report","bypass_motion"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_042', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 366.26', 'WIC § 366.26', 'Selection of Permanent Plan — Adoption or Guardianship', 'Governs the selection and implementation hearing for permanent plans when reunification fails, including adoption, guardianship, and long-term foster care.', '["Adoption is preferred permanent plan","Legal guardianship if adoption not appropriate","Long-term foster care as last resort","Parental rights terminated if adoption selected","Indian Child Welfare Act (ICWA) placement preferences apply"]', '[{"section":"366.26(b)","description":"Hearing to select permanent plan"},{"section":"366.26(c)(1)","description":"Termination of parental rights if child likely to be adopted"},{"section":"366.26(c)(3)","description":"Beneficial relationship exception to TPR"}]', '["permanency_plan","adoption_assessment","guardianship_petition","TPR_order","366.26_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_043', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 364', 'WIC § 364', 'Review Hearings — Child Not Removed', 'Governs periodic review hearings when a child remains in the home of the parent under dependency jurisdiction.', '["Review hearing within 6 months of initial disposition","Court determines if conditions justify continued jurisdiction","Agency must show by preponderance that conditions still exist","Jurisdiction terminated if conditions no longer exist"]', '[{"section":"364(c)","description":"Court shall terminate jurisdiction unless conditions still exist warranting jurisdiction"},{"section":"364(d)","description":"If child removed at review — standard removal findings required"}]', '["status_review_report","social_worker_report","court_order","364_hearing_report"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_044', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 355', 'WIC § 355', 'Court Findings at Jurisdictional Hearing', 'Establishes evidentiary standards and procedures at the jurisdictional hearing in dependency proceedings.', '["Preponderance of evidence standard for jurisdiction","Social study admissible and constitutes prima facie evidence","Hearsay in social study — corroboration may be required","Objection to specific hearsay requires corroborating evidence for sustained allegation"]', '[{"section":"355(a)","description":"Proof by preponderance of the evidence"},{"section":"355(b)","description":"Social study as prima facie evidence"},{"section":"355(c)","description":"Hearsay corroboration requirement upon objection"}]', '["jurisdiction_disposition_report","social_study","court_findings","355_hearing_transcript"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_045', 'ADVOCIS', 'STATE_STATUTE', 'CA', 'Cal. Welf. & Inst. Code § 317', 'WIC § 317', 'Appointment of Counsel for Child', 'Requires appointment of counsel for a child in dependency proceedings unless the court finds the child would not benefit from counsel.', '["Court shall appoint counsel for child unless no benefit","Counsel represents child — not parent or agency","Counsel has duty to investigate independently","May advocate position different from social worker recommendation"]', '[{"section":"317(a)","description":"Mandatory appointment of counsel for child"},{"section":"317(c)","description":"Duties of appointed counsel — investigate, advocate, appear at hearings"},{"section":"317(e)","description":"Counsel must be competent in dependency law"}]', '["appointment_order","counsel_declaration","minor_counsel_report","objection_filing"]', '["california-cps-child-welfare-audit"]', 'California Juvenile Court / DCFS', 0, 1, datetime('now'), datetime('now'));


