INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_adv_046', 'ADVOCIS', 'CASE_LAW', 'CA', 'Tarasoff v. Regents of the University of California (1976) 17 Cal.3d 425', 'Tarasoff', 'Duty to Warn — Therapist Obligation to Identifiable Victims', 'When a therapist determines or should determine that a patient presents a serious danger of violence to another, the therapist incurs an obligation to use reasonable care to protect the foreseeable victim.', '["Duty to warn identifiable potential victims of patient violence","Therapist must exercise reasonable care to protect foreseeable victim","Confidentiality yields to peril to public — protective privilege ends where public peril begins","Codified in Cal. Civ. Code § 43.92 and Cal. Evid. Code § 1024"]', '[{"section":"Tarasoff I (1974)","description":"Duty to warn — therapist must warn identifiable victim"},{"section":"Tarasoff II (1976)","description":"Expanded to duty to protect — broader obligation beyond mere warning"}]', '["threat_assessment","mandatory_report","therapist_disclosure","CPS_referral","law_enforcement_notification"]', '["california-cps-child-welfare-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));


