INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_072', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 70', 'FC § 70', 'Date of Separation — Definition', 'Defines the date of separation as the date a complete and final break in the marital relationship has occurred, requiring both expressed intent and conduct consistent with termination.', '["Date of separation requires both intent and conduct","Complete and final break in marital relationship","Expressed intent to end marriage to the other spouse","Conduct consistent with intent to end the marriage"]', '[{"section":"70(a)","description":"Date of separation defined as complete and final break"},{"section":"70(b)","description":"Requires both expressed intent and conduct consistent with ending marriage"}]', '["dissolution_petition","FL-100","FL-110","property_declaration","FL-142"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_073', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 852', 'FC § 852', 'Transmutation of Property Between Spouses', 'Transmutation of community to separate property or separate to community property requires an express written declaration by the adversely affected spouse.', '["Express written declaration required for transmutation","Must be made, joined in, consented to, or accepted by adversely affected spouse","Oral or implied transmutations invalid after 1985","Writing must expressly state change in character of property"]', '[{"section":"852(a)","description":"Transmutation requires express declaration in writing by adversely affected spouse"},{"section":"852(b)","description":"Not enforceable as between parties without compliance"},{"section":"852(e)","description":"Gifts of clothing/personal effects exempt if not substantial in value"}]', '["transmutation_agreement","interspousal_transfer","quitclaim_deed","property_declaration"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_074', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 3024', 'FC § 3024', 'Counseling Before Custody Modification', 'Court may require parents to participate in outpatient counseling with a licensed mental health professional or mediation as a condition of modifying custody or visitation.', '["Court may order counseling before custody modification","Licensed mental health professional required","Counselor may provide recommendations to court","Costs allocated between parties by court order"]', '[{"section":"3024","description":"Counseling or mediation may be required before modifying custody or visitation orders"}]', '["custody_modification","counseling_order","mediation_report","FL-300"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_075', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 3065', 'FC § 3065', 'Domestic Violence and Parenting Classes', 'Court shall require a batterer to participate in a batterer treatment program as a condition of custody or visitation. Court shall not require victim to participate in joint counseling.', '["Batterer treatment program required as condition of custody/visitation","52-week minimum batterer intervention program","No joint counseling ordered with victim of DV","Parenting class may be separate requirement","Cost borne by batterer unless hardship shown"]', '[{"section":"3065","description":"Mandatory batterer intervention program and prohibition on joint counseling with DV victim"}]', '["DV_restraining_order","custody_order","batterer_program_enrollment","parenting_class_certificate"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_076', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code §§ 4050-4076', 'FC §§ 4050-4076', 'Uniform Guideline for Determining Child Support', 'Statewide uniform guideline for calculating child support based on income of both parents, timeshare percentage, tax filing status, and allowable deductions.', '["Mandatory statewide guideline — presumed correct","Calculated from both parents net disposable income","Timeshare percentage affects support amount","Guideline may be rebutted only under FC § 4057(b) special circumstances","Income includes salary, commissions, bonuses, rental income, and imputed income from assets"]', '[{"section":"4055","description":"Algebraic formula for guideline child support"},{"section":"4057(a)","description":"Guideline amount is presumptively correct"},{"section":"4057(b)","description":"Rebuttal factors — special circumstances"},{"section":"4058","description":"Definition of annual gross income for support"},{"section":"4062","description":"Add-on expenses — childcare, health insurance, education"}]', '["FL-150","FL-155","DissoMaster_printout","child_support_order","income_declaration"]', '["california-family-law-expansion-audit"]', 'California Family Court / DCSS', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_077', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 2106', 'FC § 2106', 'Attorney Fees for Disclosure Disputes', 'Court shall impose monetary sanctions and may award attorney fees against a party who fails to comply with preliminary or final declaration of disclosure obligations.', '["Mandatory sanctions for disclosure noncompliance","Attorney fees may be awarded to compliant party","Court may preclude noncompliant party from presenting undisclosed evidence","Remedies cumulative with FC § 1101 breach of fiduciary duty"]', '[{"section":"2106(a)","description":"Sanctions for failure to comply with disclosure requirements"},{"section":"2106(b)","description":"Attorney fees and costs as sanction"},{"section":"2106(c)","description":"Preclusion sanction for undisclosed assets or income"}]', '["FL-140","FL-141","FL-142","disclosure_motion","sanctions_order"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_078', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 3600', 'FC § 3600', 'Temporary Child Support', 'Court may order any amount of child support during the pendency of a proceeding that is necessary for the support of the child.', '["Temporary support ordered during pendency of proceeding","Amount based on needs of child and ability of parents to pay","Not limited by guideline calculation — court has broad discretion","Effective from date of filing or from date ordered"]', '[{"section":"3600","description":"Temporary child support — court may order any amount necessary during proceeding"}]', '["temporary_support_order","FL-300","FL-305","FL-150","income_declaration"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_079', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Fam. Code § 4330', 'FC § 4330', 'Spousal Support Termination', 'Spousal support terminates upon death of either party, remarriage of the supported party, or further order of court. For long-term marriages, court retains jurisdiction indefinitely unless parties agree otherwise.', '["Support terminates on death, remarriage, or court order","Long-term marriage (10+ years) — court retains jurisdiction indefinitely","Short-term marriage — support presumed for half the length of marriage","Marital standard of living is benchmark","Gavron warning — supported spouse must become self-supporting"]', '[{"section":"4330(a)","description":"Court may order spousal support for any period of time"},{"section":"4330(b)","description":"Goal of self-support within reasonable time — Gavron warning"}]', '["spousal_support_order","FL-150","FL-157","vocational_evaluation","judgment"]', '["california-family-law-expansion-audit"]', 'California Family Court', 0, 1, datetime('now'), datetime('now'));

